1| <!DOCTYPE html>
2| <html lang="zh-CN">
3| <head>
4| <meta charset="UTF-8">
5| <meta name="viewport" content="width=device-width, initial-scale=1.0">
6| <title>施工现场安全隐患综合分析报告</title>
7| <style>
8| :root{
9|   --bg:#f5f7fa;
10|   --card:#ffffff;
11|   --border:#e2e8f0;
12|   --text:#1a202c;
13|   --text2:#64748b;
14|   --red:#dc2626;
15|   --orange:#ea580c;
16|   --blue:#2563eb;
17|   --green:#16a34a;
18|   --red-bg:#fef2f2;
19|   --red-bd:#fecaca;
20|   --orange-bg:#fff7ed;
21|   --orange-bd:#fed7aa;
22|   --blue-bg:#eff6ff;
23|   --blue-bd:#bfdbfe;
24|   --green-bg:#f0fdf4;
25|   --green-bd:#bbf7d0;
26| }
27| *{
28|   box-sizing:border-box;
29|   margin:0;
30|   padding:0;
31| }
32| html,body{
33|   background:var(--bg);
34|   font-family:"PingFang SC","Microsoft YaHei","Helvetica Neue",Arial,sans-serif;
35|   color:var(--text);
36|   line-height:1.7;
37|   font-size:15px;
38|   -webkit-font-smoothing:antialiased;
39| }
40| .container{
41|   max-width:800px;
42|   margin:0 auto;
43|   padding:24px 16px;
44| }
45| /* 封面 */
46| .cover{
47|   background:linear-gradient(135deg,#1e3a5f,#2563eb);
48|   color:#fff;
49|   border-radius:20px;
50|   padding:48px 32px;
51|   text-align:center;
52|   margin-bottom:24px;
53|   box-shadow:0 8px 32px rgba(37,99,235,.25);
54| }
55| .cover .logo{
56|   width:64px;
57|   height:64px;
58|   background:rgba(255,255,255,.15);
59|   border-radius:16px;
60|   display:flex;
61|   align-items:center;
62|   justify-content:center;
63|   margin:0 auto 16px;
64|   font-size:28px;
65| }
66| .cover h1{
67|   font-size:1.6rem;
68|   font-weight:700;
69|   margin-bottom:8px;
70|   letter-spacing:.5px;
71| }
72| .cover .sub{
73|   font-size:.9rem;
74|   opacity:.85;
75|   margin-bottom:24px;
76| }
77| .badge-row{
78|   display:flex;
79|   gap:10px;
80|   justify-content:center;
81|   flex-wrap:wrap;
82| }
83| .badge{
84|   padding:6px 16px;
85|   border-radius:100px;
86|   font-size:.8rem;
87|   font-weight:600;
88|   letter-spacing:.3px;
89| }
90| .badge-red{background:var(--red-bg);border:1px solid var(--red-bd);color:var(--red)}
91| .badge-orange{background:var(--orange-bg);border:1px solid var(--orange-bd);color:var(--orange)}
92| .badge-blue{background:var(--blue-bg);border:1px solid var(--blue-bd);color:var(--blue)}
93| .badge-green{background:var(--green-bg);border:1px solid var(--green-bd);color:var(--green)}
94| .stat-row{
95|   display:flex;
96|   gap:12px;
97|   margin-top:24px;
98|   justify-content:center;
99|   flex-wrap:wrap;
100| }
101| .stat{
102|   background:rgba(255,255,255,.12);
103|   border-radius:12px;
104|   padding:16px 24px;
105|   text-align:center;
106|   min-width:80px;
107| }
108| .stat .num{
109|   font-size:2rem;
110|   font-weight:800;
111|   line-height:1.1;
112| }
113| .stat .label{
114|   font-size:.75rem;
115|   opacity:.8;
116|   margin-top:4px;
117| }
118| /* 卡片 */
119| .card{
120|   background:var(--card);
121|   border-radius:16px;
122|   padding:24px;
123|   margin-bottom:20px;
124|   box-shadow:0 2px 8px rgba(0,0,0,.06);
125|   border:1px solid var(--border);
126| }
127| .card-header{
128|   display:flex;
129|   align-items:center;
130|   gap:10px;
131|   margin-bottom:18px;
132|   padding-bottom:14px;
133|   border-bottom:1px solid var(--border);
134| }
135| .card-header .icon{
136|   width:36px;
137|   height:36px;
138|   border-radius:10px;
139|   display:flex;
140|   align-items:center;
141|   justify-content:center;
142|   font-size:18px;
143| }
144| .card-header h2{
145|   font-size:1.05rem;
146|   font-weight:700;
147|   color:var(--text);
148| }
149| /* 信息网格 */
150| .info-grid{
151|   display:grid;
152|   grid-template-columns:repeat(2,1fr);
153|   gap:12px 24px;
154| }
155| .info-item{
156|   display:flex;
157|   gap:8px;
158|   font-size:.9rem;
159| }
160| .info-label{
161|   color:var(--text2);
162|   min-width:72px;
163|   flex-shrink:0;
164| }
165| .info-value{
166|   color:var(--text);
167|   font-weight:500;
168| }
169| /* 场景标签 */
170| .scene-tags{
171|   display:flex;
172|   gap:8px;
173|   flex-wrap:wrap;
174| }
175| .scene-tag{
176|   padding:5px 12px;
177|   background:var(--blue-bg);
178|   border:1px solid var(--blue-bd);
179|   border-radius:8px;
180|   font-size:.8rem;
181|   color:var(--blue);
182|   font-weight:500;
183| }
184| /* 隐患项 */
185| .hazard-item{
186|   padding:16px 0;
187|   border-bottom:1px solid var(--border);
188| }
189| .hazard-item:last-child{
190|   border-bottom:none;
191|   padding-bottom:0;
192| }
193| .hazard-header{
194|   display:flex;
195|   align-items:flex-start;
196|   gap:12px;
197|   margin-bottom:10px;
198| }
199| .hazard-num{
200|   width:28px;
201|   height:28px;
202|   border-radius:50%;
203|   display:flex;
204|   align-items:center;
205|   justify-content:center;
206|   font-weight:700;
207|   font-size:.75rem;
208|   flex-shrink:0;
209| }
210| .hazard-num.red{background:var(--red);color:#fff}
211| .hazard-num.orange{background:var(--orange);color:#fff}
212| .hazard-num.blue{background:var(--blue);color:#fff}
213| .hazard-num.green{background:var(--green);color:#fff}
214| .hazard-content{
215|   flex:1;
216| }
217| .hazard-desc{
218|   font-size:.95rem;
219|   font-weight:600;
220|   color:var(--text);
221|   margin-bottom:6px;
222| }
223| .level-tag{
224|   display:inline-block;
225|   padding:3px 10px;
226|   border-radius:6px;
227|   font-size:.75rem;
228|   font-weight:700;
229| }
230| .level-severe{background:var(--red-bg);color:var(--red);border:1px solid var(--red-bd)}
231| .level-general{background:var(--orange-bg);color:var(--orange);border:1px solid var(--orange-bd)}
232| .level-suggest{background:var(--blue-bg);color:var(--blue);border:1px solid var(--blue-bd)}
233| .clause-list{
234|   margin-top:10px;
235|   padding:12px;
236|   background:#f8fafc;
237|   border-radius:10px;
238|   border:1px solid var(--border);
239| }
240| .clause-item{
241|   margin-bottom:8px;
242|   font-size:.85rem;
243|   line-height:1.6;
244| }
245| .clause-item:last-child{
246|   margin-bottom:0;
247| }
248| .clause-item strong{
249|   color:var(--blue);
250|   font-weight:600;
251| }
252| .clause-item .std-name{
253|   color:var(--text2);
254| }
255| .clause-text{
256|   color:var(--text);
257|   margin-top:2px;
258| }
259| .fix-item{
260|   margin-top:8px;
261|   padding:8px 12px;
262|   background:#fff;
263|   border-radius:8px;
264|   border-left:3px solid var(--blue);
265|   font-size:.85rem;
266|   color:var(--text);
267| }
268| /* 统计 */
269| .stats-grid{
270|   display:grid;
271|   grid-template-columns:repeat(3,1fr);
272|   gap:12px;
273|   margin-bottom:16px;
274| }
275| .stat-box{
276|   text-align:center;
277|   padding:16px;
278|   border-radius:12px;
279|   font-size:.85rem;
280| }
281| .stat-box.red{background:var(--red-bg);border:1px solid var(--red-bd)}
282| .stat-box.orange{background:var(--orange-bg);border:1px solid var(--orange-bd)}
283| .stat-box.blue{background:var(--blue-bg);border:1px solid var(--blue-bd)}
284| .stat-box .num{font-size:1.8rem;font-weight:800;line-height:1}
285| .stat-box .label{margin-top:4px;color:var(--text2)}
286| .priority-block{
287|   margin-bottom:12px;
288| }
289| .priority-block:last-child{margin-bottom:0}
290| .priority-header{
291|   display:flex;
292|   align-items:center;
293|   gap:8px;
294|   margin-bottom:8px;
295| }
296| .priority-label{
297|   padding:4px 12px;
298|   border-radius:6px;
299|   font-size:.75rem;
300|   font-weight:700;
301|   color:#fff;
302| }
303| .priority-label.p0{background:var(--red)}
304| .priority-label.p1{background:var(--orange)}
305| .priority-label.p2{background:var(--blue)}
306| .priority-items{
307|   padding:12px;
308|   background:#f8fafc;
309|   border-radius:10px;
310|   border:1px solid var(--border);
311| }
312| .priority-item{
313|   display:flex;
314|   gap:8px;
315|   font-size:.85rem;
316|   margin-bottom:6px;
317| }
318| .priority-item:last-child{margin-bottom:0}
319| .priority-item .num{
320|   color:var(--text2);
321|   font-weight:600;
322| }
323| .priority-item .text{color:var(--text)}
324| /* 图片 */
325| .image-section{
326|   text-align:center;
327|   padding:20px;
328|   background:var(--card);
329|   border-radius:16px;
330|   margin-bottom:20px;
331|   box-shadow:0 2px 8px rgba(0,0,0,.06);
332|   border:1px solid var(--border);
333| }
334| .image-section img{
335|   max-width:100%;
336|   max-height:500px;
337|   border-radius:12px;
338|   box-shadow:0 4px 16px rgba(0,0,0,.1);
339| }
340| /* 页脚 */
341| .footer{
342|   text-align:center;
343|   padding:24px;
344|   color:var(--text2);
345|   font-size:.8rem;
346|   border-top:1px solid var(--border);
347|   margin-top:24px;
348| }
349| .footer .company{
350|   font-weight:600;
351|   color:var(--blue);
352|   margin-bottom:4px;
353| }
354| @media(max-width:640px){
355|   .info-grid{grid-template-columns:1fr}
356|   .stats-grid{grid-template-columns:1fr}
357|   .cover{padding:36px 20px}
358|   .cover h1{font-size:1.3rem}
359|   .stat-row{gap:8px}
360|   .stat{padding:12px 16px;min-width:70px}
361| }
362| </style>
363| </head>
364| <body>
365| <div class="container">
366| 
367| <!-- 封面 -->
368| <div class="cover">
369|   <div class="logo">🏗️</div>
370|   <h1>施工现场安全隐患综合分析报告</h1>
371|   <div class="sub">中国电建成都院智成安监系统</div>
372|   <div class="badge-row" id="summaryBadges"></div>
373|   <div class="stat-row" id="summaryStats"></div>
374| </div>
375| 
376| <!-- 基本信息 -->
377| <div class="card">
378|   <div class="card-header">
379|     <div class="icon" style="background:var(--blue-bg)">📋</div>
380|     <h2>基本信息</h2>
381|   </div>
382|   <div class="info-grid" id="basicInfo"></div>
383| </div>
384| 
385| <!-- 场景认定 -->
386| <div class="card">
387|   <div class="card-header">
388|     <div class="icon" style="background:var(--green-bg)">🎯</div>
389|     <h2>场景认定</h2>
390|   </div>
391|   <div class="scene-tags" id="sceneTags"></div>
392| </div>
393| 
394| <!-- 隐患清单 -->
395| <div class="card">
396|   <div class="card-header">
397|     <div class="icon" style="background:var(--red-bg)">⚠️</div>
398|     <h2>隐患清单</h2>
399|   </div>
400|   <div id="hazardList"></div>
401| </div>
402| 
403| <!-- 综合评价 -->
404| <div class="card">
405|   <div class="card-header">
406|     <div class="icon" style="background:var(--orange-bg)">📊</div>
407|     <h2>综合评价</h2>
408|   </div>
409|   <div class="stats-grid" id="evalStats"></div>
410|   <div id="evalNote"></div>
411| </div>
412| 
413| <!-- 整改优先级 -->
414| <div class="card">
415|   <div class="card-header">
416|     <div class="icon" style="background:var(--blue-bg)">🎯</div>
417|     <h2>整改优先级</h2>
418|   </div>
419|   <div id="priorityList"></div>
420| </div>
421| 
422| <!-- 现场照片 -->
423| <div class="image-section" id="imageSection"></div>
424| 
425| <!-- 页脚 -->
426| <div class="footer">
427|   <div class="company">中国电建成都院智成安监系统</div>
428|   <div id="reportFooter"></div>
429| </div>
430| 
431| </div>
432| </body>
433| </html>

